"""Nova base exception handling.



Includes decorator for re-raising Nova-type exceptions.



SHOULD include dedicated exception logging.



"""



import functools

import sys



import novaclient.exceptions

import webob.exc



from nova import log as logging



LOG = logging.getLogger(__name__)





class ConvertedException(webob.exc.WSGIHTTPException):

    def __init__(self, code=0, title="", explanation=""):

        self.code = code

        self.title = title

        self.explanation = explanation

        super(ConvertedException, self).__init__()





class ProcessExecutionError(IOError):

    def __init__(self, stdout=None, stderr=None, exit_code=None, cmd=None,

                 description=None):

        self.exit_code = exit_code

        self.stderr = stderr

        self.stdout = stdout

        self.cmd = cmd

        self.description = description



        if description is None:

            description = _('Unexpected error while running command.')

        if exit_code is None:

            exit_code = '-'

        message = _('%(description)s\nCommand: %(cmd)s\n'

                    'Exit code: %(exit_code)s\nStdout: %(stdout)r\n'

                    'Stderr: %(stderr)r') % locals()

        IOError.__init__(self, message)





class Error(Exception):

    pass





class EC2APIError(Error):

    def __init__(self, message='Unknown', code=None):

        self.msg = message

        self.code = code

        if code:

            outstr = '%s: %s' % (code, message)

        else:

            outstr = '%s' % message

        super(EC2APIError, self).__init__(outstr)





class DBError(Error):

    """Wraps an implementation specific exception."""

    def __init__(self, inner_exception=None):

        self.inner_exception = inner_exception

        super(DBError, self).__init__(str(inner_exception))





def wrap_db_error(f):

    def _wrap(*args, **kwargs):

        try:

            return f(*args, **kwargs)

        except UnicodeEncodeError:

            raise InvalidUnicodeParameter()

        except Exception, e:

            LOG.exception(_('DB exception wrapped.'))

            raise DBError(e)

    _wrap.func_name = f.func_name

    return _wrap





def wrap_exception(notifier=None, publisher_id=None, event_type=None,

                   level=None):

    """This decorator wraps a method to catch any exceptions that may

    get thrown. It logs the exception as well as optionally sending

    it to the notification system.

    """

    # TODO(sandy): Find a way to import nova.notifier.api so we don't have

    # to pass it in as a parameter. Otherwise we get a cyclic import of

    # nova.notifier.api -> nova.utils -> nova.exception :(

    # TODO(johannes): Also, it would be nice to use

    # utils.save_and_reraise_exception() without an import loop

    def inner(f):

        def wrapped(*args, **kw):

            try:

                return f(*args, **kw)

            except Exception, e:

                # Save exception since it can be clobbered during processing

                # below before we can re-raise

                exc_info = sys.exc_info()



                if notifier:

                    payload = dict(args=args, exception=e)

                    payload.update(kw)



                    # Use a temp vars so we don't shadow

                    # our outer definitions.

                    temp_level = level

                    if not temp_level:

                        temp_level = notifier.ERROR



                    temp_type = event_type

                    if not temp_type:

                        # If f has multiple decorators, they must use

                        # functools.wraps to ensure the name is

                        # propagated.

                        temp_type = f.__name__



                    notifier.notify(publisher_id, temp_type, temp_level,

                                    payload)



                # re-raise original exception since it may have been clobbered

                raise exc_info[0], exc_info[1], exc_info[2]



        return functools.wraps(f)(wrapped)

    return inner





class NovaException(Exception):

    """Base Nova Exception



    To correctly use this class, inherit from it and define

    a 'message' property. That message will get printf'd

    with the keyword arguments provided to the constructor.



    """

    message = _("An unknown exception occurred.")

    code = 500

    headers = {}

    safe = False



    def __init__(self, message=None, **kwargs):

        self.kwargs = kwargs



        if 'code' not in self.kwargs:

            try:

                self.kwargs['code'] = self.code

            except AttributeError:

                pass



        if not message:

            try:

                message = self.message % kwargs



            except Exception as e:

                # at least get the core message out if something happened

                message = self.message



        super(NovaException, self).__init__(message)





