    position: relative;

    display: inline-block;

    width: 2em;

    height: 2em;

    line-height: 2em;

    vertical-align: middle;

}

%fa-stack-1x,

%fa-stack-2x {

    position: absolute;

    left: 0;

    width: 100%;

    text-align: center;

}

