function strip_webroot ($path) {

                self::$webroot = self::$webroot ? self::$webroot : '/' . conf('Paths','filemanager_path') . '/';

		$root = preg_quote (self::$webroot, '/');

		$root = preg_replace ('|^\\\/|', '\\/?', $root);

		return preg_replace ('/^' . $root . '/', '', $path);

