mm_log_handler(LogLevel level, const char *msg, void *ctx)

{

	Buffer log_msg;

	struct monitor *mon = (struct monitor *)ctx;



	if (mon->m_log_sendfd == -1)

		fatal("%s: no log channel", __func__);



