static unsigned long mmap_base(void)

{

	unsigned long gap = rlimit(RLIMIT_STACK);



	if (gap < MIN_GAP)

		gap = MIN_GAP;

	else if (gap > MAX_GAP)

		gap = MAX_GAP;



	return PAGE_ALIGN(TASK_SIZE - gap - mmap_rnd());

