  'DISCONNECT',

  'EVENT',

  'ACK',

  'ERROR',

  'BINARY_EVENT',

  'BINARY_ACK'

];



/**

 * Packet type `connect`.

 *

 * @api public

 */



exports.CONNECT = 0;



/**

 * Packet type `disconnect`.

 *

 * @api public

 */



exports.DISCONNECT = 1;



/**

 * Packet type `event`.

 *

 * @api public

 */



exports.EVENT = 2;



/**

 * Packet type `ack`.

 *

 * @api public

 */



exports.ACK = 3;



/**

 * Packet type `error`.

 *

 * @api public

 */



exports.ERROR = 4;



/**

 * Packet type 'binary event'

 *

 * @api public

 */



exports.BINARY_EVENT = 5;



/**

 * Packet type `binary ack`. For acks with binary arguments.

 *

 * @api public

 */



exports.BINARY_ACK = 6;



