    hasGrant: function(node, grants) {

        var attr = node.attributes,

            condition = false;



        if(attr && attr.leaf) {

            condition = true;

            Ext.each(grants, function(grant) {

                condition = condition && attr.container.account_grants[grant];

            }, this);

        }



        return condition;

