		X86_EFLAGS_SF;

	flags &= *reg_rmw(ctxt, VCPU_REGS_RAX) >> 8;



	ctxt->eflags &= ~0xffUL;

	ctxt->eflags |= flags | X86_EFLAGS_FIXED;

	return X86EMUL_CONTINUE;

