int sc_append_path_id(sc_path_t *dest, const u8 *id, size_t idlen)

{

	if (dest->len + idlen > SC_MAX_PATH_SIZE)

		return SC_ERROR_INVALID_ARGUMENTS;

	memcpy(dest->value + dest->len, id, idlen);

	dest->len += idlen;

