static int set_msg_len(u8 *block, unsigned int msglen, int csize)

{

	__be32 data;



	memset(block, 0, csize);

	block += csize;



	if (csize >= 4)

		csize = 4;

	else if (msglen > (1 << (8 * csize)))

		return -EOVERFLOW;



	data = cpu_to_be32(msglen);

	memcpy(block - csize, (u8 *)&data + 4 - csize, csize);



	return 0;

