{

	/* icmpv6_notify checks 8 bytes can be pulled, icmp6hdr is 8 bytes */

	struct icmp6hdr *icmp6 = (struct icmp6hdr *) (skb->data + offset);

	struct net *net = dev_net(skb->dev);



